COPY public."PracticalTask" (id, "moduleId", title, description, "taskType", "checkType", "maxScore", "createdAt", "updatedAt", "interactiveExpectedAnswer", "expectedCommand", "expectedAnswerPattern", "consoleScenario", "allowedFileTypes", "maxFileSizeMb", "minLength", instruction, "scenarioData") FROM stdin;
cmp45quav001jn52b7x5fseeo	cmp45quat0006n52bxjqury8j	Ситуации: персональные данные, риск и безопасное действие	Две короткие бытовые истории. В каждой отметьте: есть ли персональные данные, насколько это рискованно и что сделать безопаснее всего.\n\nОценка ставится автоматически — нужно совпасть с учебным эталоном по всем трём полям.	SITUATION_CHOICE	AUTO	20	2026-05-13 14:31:23.62	2026-05-28 02:13:37.922	\N	\N	\N	\N	\N	\N	10	\N	{"hints": ["Персональные данные — то, по чему вас можно узнать: ФИО, паспорт, телефон, почта, логин, адрес и т.п.", "Общий чат курса — публичный канал: туда не несут сканы документов."], "criteria": "Нужно полное совпадение с эталоном по каждой ситуации (все три ответа).", "situations": [{"id": "s1", "text": "В общем чате курса одногруппник просит сфоткать разворот паспорта «для проверки личности».", "choices": {"risk": [{"id": "risk_high", "label": "Высокий риск утечки"}, {"id": "risk_low", "label": "Низкий риск"}], "safeAction": [{"id": "act_refuse", "label": "Отказаться и предложить официальный канал / преподавателю"}, {"id": "act_send", "label": "Прислать фото в общий чат без вопросов"}], "personalData": [{"id": "pd_yes", "label": "Да, это персональные данные"}, {"id": "pd_no", "label": "Нет, это не персональные данные"}]}, "expected": {"risk": "risk_high", "safeAction": "act_refuse", "personalData": "pd_yes"}}, {"id": "s2", "text": "В анкете на выставку ты указываешь только город, без ФИО и телефона — как разрешили организаторы.", "choices": {"risk": [{"id": "risk_med", "label": "Средний риск (зависит от контекста)"}, {"id": "risk_min", "label": "Минимальный риск при таком объёме"}], "safeAction": [{"id": "act_ok", "label": "Так можно, если политика мероприятия это допускает"}, {"id": "act_bad", "label": "Нужно указать ещё и паспортные данные «для формальности»"}], "personalData": [{"id": "pd_coarse", "label": "Скорее обезличенные/грубые данные"}, {"id": "pd_full", "label": "Точно персональные данные как в паспорте"}]}, "expected": {"risk": "risk_min", "safeAction": "act_ok", "personalData": "pd_coarse"}}]}
cmp45qudw004kn52b5som0ptj	cmp45qudv0035n52bxqz8w03l	Анализ паролей: слабый, средний, надёжный	Три выдуманных пароля — расставьте им уровень: слабый, средний или надёжный. Смотри на длину, шаблоны вроде клавиатурного ряда и не повторяй такие пароли в жизни.\n\nПроверка автоматическая.	PASSWORD_ANALYSIS	AUTO	20	2026-05-13 14:31:23.732	2026-05-28 02:13:37.957	\N	\N	\N	\N	\N	\N	10	\N	{"hints": ["Слабый — короткий, только цифры или привычный ряд на клавиатуре.", "Средний — длиннее, но узнаваемое слово + год или «Qwerty…».", "Надёжный в задании — длинный набор разных типов символов без банального слова (только для тренировки на платформе)."], "items": [{"id": "p1", "note": "Только цифры, короткий шаблон.", "sample": "12345678", "expectedStrength": "WEAK"}, {"id": "p2", "note": "Клавиатурный паттерн + год.", "sample": "Qwerty2024!", "expectedStrength": "MEDIUM"}, {"id": "p3", "note": "Длина и смесь классов символов (учебный пример).", "sample": "k9#mP2$vL8@nQ1!wR5z", "expectedStrength": "STRONG"}], "criteria": "Для каждого пароля должен быть выбран нужный уровень (слабый / средний / надёжный) по эталону задания."}
cmp45qull00dln52bs28hgcdi	cmp45qulk00c6n52bgzc26fbu	Анализ ссылок: безопасные и подозрительные	Пять учебных ссылок в таблице. Решите для каждой: ок или подозрительно; у подозрительных укажите причину и пару предложений своими словами (домен, https, опечатка).\n\nСтроки вымышленные, сайты не открываются — только разбор текста.	URL_ANALYSIS	AUTO	20	2026-05-13 14:31:24.008	2026-05-28 02:13:38.056	\N	\N	\N	\N	\N	\N	10	\N	{"urls": [], "hints": ["Смотрите на начало адреса (http/https), опечатки в имени сайта и «главный» домен справа перед первым слэшем.", "Примеры вроде college.ru и example.com придуманы для тренировки."], "criteria": "Все ссылки классифицированы верно, у подозрительных указана причина, в тексте есть нужные слова; для зачёта обычно от 9/10 баллов по ссылкам.", "explanationPattern": "(домен|https|http|поддел|опечатк|ссылк|подозрит|протокол|поддомен)", "explanationMinLength": 35}
cmp45qufd007ln52bahw0rqz2	cmp45qufc0068n52btqvxt8z3	Разбор учебного «фишингового» письма	Откройте письмо и отметьте подозрительные места (отправитель, срочность, ссылка, просьба пароля…). Нажмите «Проверить»: до пяти баллов; четыре и пять засчитываются автоматически.\n\nАдреса и названия вымышленные.	PHISHING_ANALYSIS	AUTO	20	2026-05-13 14:31:23.784	2026-05-28 02:13:37.994	\N	\N	\N	\N	\N	\N	10	\N	{"hints": ["Сверьте домен отправителя с тем, как обычно пишет ваша учебная организация.", "Частая связка: «срочно» + «аккаунт заблокируют» + ссылка не туда + «напишите пароль»."], "criteria": "5/5 — отлично; 4/5 — хорошо; 3/5 — повторите тему; ниже 3 баллов зачёт не сохранится — попробуйте ещё раз.", "correctFlagIds": ["sender", "urgency", "suspicious_link", "password_request", "threat_block"]}
cmp45quqj00jnn52be63hjoch	cmp45quqi00i8n52bk3nm0ood	Криптография для новичков: Цезарь, Base64, хеши	Три маленьких шага: сдвиг Цезаря, раскодировать Base64, сравнить два учебных хеша и словами сказать, что значит совпадение или различие. Без «взломов» и без реальных паролей.\n\nПроверка автоматическая.	CRYPTO_TASK	AUTO	20	2026-05-13 14:31:24.186	2026-05-28 02:13:38.116	\N	\N	\N	\N	\N	\N	10	\N	{"hints": ["Цезарь: если при шифровании сдвиг +3, при расшифровке каждую букву сдвигаете на три позиции назад по алфавиту задания.", "Base64 — это «упаковка» в текст, не секрет; на выходе должна читаться обычная фраза.", "Если хеши разные — файлы не одинаковые; в пояснении упомяните хеш или отличие."], "criteria": "Верно Цезарь, Base64, ответ про хеши и короткое пояснение не короче 20 символов со словом про хеш или про отличие."}
cmp45qurz00mon52bz0r7b12h	cmp45qury00lbn52b1eh82oo2	Мини-SOC: анализ логов	Вымышленный журнал входов. Найдите подозрительную цепочку, выберите тип инцидента из списка и кратко опишите вывод как сотрудник защиты: нейтрально, без инструкций «как повторить».\n\nПроверка по кнопке «Проверить».	LOG_ANALYSIS	AUTO	20	2026-05-13 14:31:24.238	2026-05-28 02:13:38.143	\N	\N	\N	\N	\N	\N	60	\N	{"hints": ["Смотрите на порядок: несколько неудачных входов, потом успешный вход, потом запрос сброса пароля.", "Пишите спокойно: «похоже на…», «рекомендую проверить…», без пошагового «как взломать»."], "criteria": "Нужен верный тип инцидента для учебного сценария (подбор пароля) и вывод с ключевыми словами не короче минимальной длины.", "logLines": [], "autoKeywords": ["неудач", "успеш", "сброс"], "conclusionMinLength": 50}
cmp45quoa00gmn52bjkqvegl4	cmp45quo900f9n52btwu04puk	Учебная консоль: ping и объяснение вывода	Это симулятор: команды не уходят в интернет и не трогают вашу систему. Сначала можно help, потом выполните ровно ту команду, что внизу, и объясните вывод простыми словами.\n\nПроверка автоматическая.	TRAINING_CONSOLE	AUTO	20	2026-05-13 14:31:24.105	2026-05-28 02:13:38.086	\N	ping example.com	(ttl|time|мс|ms|icmp|ответ|адрес|ip|пакет)	Шаги:\n1) Введите ровно: ping example.com\n2) В объяснении напишите, что ответы идут с учебного IP и в выводе есть время отклика (мс) и TTL.	\N	\N	24	\N	{"hints": ["Если забыли синтаксис — help.", "В тексте лучше пересказать то, что реально увидели в окне симулятора."], "criteria": "Команда как в задании; объяснение не короче минимума и содержит слова из проверки (см. подсказки к полю ответа)."}
cmp45qugp00akn52bymjik37w	cmp45qugo0097n52b9jvtf14k	Чек-лист защиты устройства	Отметьте пять базовых пунктов гигиены ПК. Потом одним коротким текстом опишите, что из этого делаете вы или что сделали бы на своём ноутбуке — без шуток про «вирусы себе поставить».\n\nПроверка: галочки и текст по правилам задания.	CHECKLIST	AUTO	20	2026-05-13 14:31:23.833	2026-05-28 02:13:38.026	\N	\N	\N	\N	\N	\N	10	\N	{"hints": ["На занятии считаем, что все пять пунктов — норма для учебной станции.", "В ответе встретится хотя бы одно из слов: обновления, антивирус, блокировка, резерв, USB или флешка."], "items": [{"id": "updates", "label": "Автоматические обновления ОС и приложений включены"}, {"id": "lock", "label": "Блокировка экрана с PIN/паролем при простое"}, {"id": "antivirus", "label": "Антивирус / встроенная защита активна"}, {"id": "backup", "label": "Регулярные резервные копии важных данных"}, {"id": "usb", "label": "Ограничение неизвестных USB-накопителей (политика организации)"}], "criteria": "Все пункты отмечены; ответ не короче минимума и проходит проверку по ключевым словам.", "requiredIds": ["updates", "lock", "antivirus", "backup", "usb"], "reflectionPattern": "(обновлен|антивирус|блокировк|резерв|usb|флеш)", "reflectionMinLength": 40}
